import { WithDataId } from '@/types/withDataId';
import {
  Tabs as BaseTabs,
  Tab as BaseTab,
  TabList as BaseTabList,
  TabPanel as BaseTabPanel,
} from './BaseTabs';

export type TabsProps = React.ComponentPropsWithRef<typeof BaseTabs>;
export function Tabs(props: TabsProps) {
  return <BaseTabs {...props} />;
}

Tabs.Panel = TabPanel;
Tabs.List = TabList;
Tabs.Item = Tab;

export type TabProps = React.ComponentPropsWithoutRef<typeof BaseTab> &
  WithDataId;
export function Tab(props: TabProps) {
  return <BaseTab {...props} />;
}

export type TabListProps = React.ComponentPropsWithoutRef<typeof BaseTabList>;
export function TabList(props: TabListProps) {
  return <BaseTabList {...props} />;
}

export type TabPanelProps = React.ComponentPropsWithRef<typeof BaseTabPanel>;
export function TabPanel(props: TabPanelProps) {
  return <BaseTabPanel {...props} />;
}
